import { graphql } from 'gatsby';
import Layout from '../layout';

import Head from 'components/head';
import styled from '@emotion/styled';
import PinnedThumbnail from 'components/pinned-thumbnail';

const Index = function ({
  location: { search },
  data: {
    site: {
      siteMetadata: { title, description, siteUrl },
    },
    allMarkdownRemark: { edges },
  },
}: any) {
  console.log(edges[0]);
  return (
    <Layout title={title} description={description} url={siteUrl}>
      <Head url={siteUrl} />
      <PinnedWrapper>
        <PinnedTitle
          src="https://user-images.githubusercontent.com/79887293/224006290-eda97870-b68b-443e-bbc3-9b3489a39c35.png"
          alt="pinned"
        />
        <PostArea>
          <PinnedThumbnail {...edges[0].node} />
          <PinnedThumbnail {...edges[5].node} />
          <PinnedThumbnail {...edges[6].node} />
          <PinnedThumbnail {...edges[3].node} />
        </PostArea>

        <a href="/blog">
          <ReadMore>{`Read More Posts >`}</ReadMore>
        </a>
      </PinnedWrapper>

      <Margin />
    </Layout>
  );
};

export default Index;

const PinnedWrapper = styled.div`
  width: 100%;
  height: 480px;

  display: flex;
  flex-direction: column;
  justify-content: space-between;

  margin: 0 auto;
  margin-top: 57px;
  margin-bottom: 18px;

  @media (max-width: 700px) {
    width: 100%;
    height: inherit;
    padding: 0 32px;
  }
`;

const PinnedTitle = styled.img`
  width: 109px;

  @media (max-width: 700px) {
    width: 88px;
  }
`;

const PostArea = styled.div`
  width: 100%;
  height: 450px;
  margin-bottom: 24px;

  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  flex-wrap: wrap;

  @media (max-width: 700px) {
    width: 100%;
    height: inherit;
    margin-top: 24px;
  }
`;

const ReadMore = styled.span`
  margin-top: 32px;

  font-size: 14px;
  text-decoration: underline;
`;

const Margin = styled.div`
  height: 48px;
`;

export const getPostList = graphql`
  query getPostList {
    site {
      siteMetadata {
        title
        description
        siteUrl
      }
    }
    allMarkdownRemark(
      sort: { order: DESC, fields: [frontmatter___date, frontmatter___title] }
      filter: {
        frontmatter: { categories: { ne: null }, draft: { eq: false } }
      }
    ) {
      edges {
        node {
          id
          fields {
            slug
          }
          frontmatter {
            title
            summary
            date(formatString: "MMMM DD, YYYY")
            categories
            thumbnail {
              childImageSharp {
                gatsbyImageData
              }
            }
            draft
          }
        }
      }
    }
    file(name: { eq: "profile-image" }) {
      childImageSharp {
        gatsbyImageData(width: 120, height: 120)
      }
      publicURL
    }
  }
`;
